// ======================================================
// 1ï¸â£ INPUT
// ======================================================
const items = $input.all();

const MAX_CHARS = 3000;
const BATCH_THRESHOLD = 25000;

// ======================================================
// 2ï¸â£ HTML â TEXT CLEANER
// ======================================================
function htmlToText(html) {
  if (!html) return "";

  return html
    .replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, "")
    .replace(/<style[\s\S]*?>[\s\S]*?<\/style>/gi, "")

    // remove quoted blocks early noise reduction
    .replace(/<div class="gmail_quote"[\s\S]*?<\/div>/gi, "")
    .replace(/<blockquote[\s\S]*?<\/blockquote>/gi, "")

    .replace(/<br\s*\/?>/gi, "\n")
    .replace(/<\/p>/gi, "\n")
    .replace(/<\/div>/gi, "\n")

    .replace(/<[^>]+>/g, "")

    // decode entities
    .replace(/&nbsp;|&#x202F;|\u202F|\u00A0/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")

    // remove unicode junk
    .replace(/[\u00AD\u200B-\u200D\u2060]/g, "")

    .replace(/\n{3,}/g, "\n\n")
    .replace(/\s{2,}/g, " ")
    .trim();
}

// ======================================================
// 3ï¸â£ ð¨ HTML-FIRST THREAD SPLITTER (FIXED CORE)
// ======================================================
function splitLatestAndQuoted(html) {
  if (!html) return { latest: "", quoted: "" };

  const markers = [
    /<blockquote[\s\S]*?>/i,
    /On\s.+wrote:/i,
    /Le\s.+a\sÃ©crit\s:/i,
    /-----Original Message-----/i
  ];

  let splitIndex = html.length;

  for (const m of markers) {
    const match = html.match(m);
    if (match?.index !== undefined && match.index < splitIndex) {
      splitIndex = match.index;
    }
  }

  return {
    latest: html.slice(0, splitIndex),
    quoted: html.slice(splitIndex)
  };
}

// ======================================================
// 4ï¸â£ SAFE SIGNATURE REMOVAL (FIXED - NO CONTENT LOSS)
// ======================================================
function removeSignature(text) {
  const patterns = [
    /\n--\s*\n/,
    /\nkind regards[, ]*/i,
    /\nbest regards[, ]*/i,
    /\nregards[, ]*/i,
    /\nsincerely[, ]*/i
  ];

  let cutIndex = text.length;

  for (const p of patterns) {
    const match = text.match(p);
    if (match?.index !== undefined && match.index < cutIndex) {
      cutIndex = match.index;
    }
  }

  return text.substring(0, cutIndex).trim();
}

// ======================================================
// 5ï¸â£ LATEST MESSAGE PIPELINE (FIXED ORDER)
// ======================================================
function extractLatestMessage(html) {
  if (!html) return "";

  // STEP 1: split BEFORE text conversion (CRITICAL FIX)
  const { latest } = splitLatestAndQuoted(html);

  // STEP 2: convert only latest block
  let text = htmlToText(latest);

  // STEP 3: remove quoted lines
  text = text
    .split("\n")
    .filter(line => !line.trim().startsWith(">"))
    .join("\n");

  // STEP 4: remove footer noise ONLY
  text = text
    .replace(/\[image:[^\]]+\]/gi, "")
    .replace(/\[.*?\]/g, "")
    .replace(/cid:.*?\b/gi, "")
    .replace(/https?:\/\/\S+/gi, "")
    .replace(/<http[^>]+>/gi, "");

  // STEP 5: signature removal (safe)
  text = removeSignature(text);

  return text
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

// ======================================================
// 6ï¸â£ FULL THREAD CLEANER
// ======================================================
function cleanThreadHistory(html) {
  if (!html) return "";

  return htmlToText(html)
    .replace(/\[.*?\]/g, "")
    .replace(/<http[^>]+>/gi, "")
    .replace(/https?:\/\/\S+/gi, "")
    .replace(/\+?\d[\d\s\-().]{7,}/g, "")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

// ======================================================
// 7ï¸â£ SPLITTER
// ======================================================
function splitByChars(text, maxChars) {
  if (!text) return [];

  const batches = [];
  let start = 0;
  let index = 1;

  while (start < text.length) {
    let end = start + maxChars;

    if (end >= text.length) {
      batches.push({
        batch_index: index,
        text: text.slice(start).trim()
      });
      break;
    }

    let safeEnd = text.lastIndexOf(" ", end);
    if (safeEnd <= start) safeEnd = end;

    batches.push({
      batch_index: index,
      text: text.slice(start, safeEnd).trim()
    });

    start = safeEnd + 1;
    index++;
  }

  return batches;
}

// ======================================================
// 8ï¸â£ ROUTING
// ======================================================
function getEmailProcessor(toAddress) {
  if (!toAddress) return "unknown";

  const email = toAddress.toLowerCase();

  if (email === "marblebeeltd@gmail.com") return "sales_manager";
  if (email === "marblebee1@gmail.com") return "sales_emily";
  if (email === "marblebee2025@gmail.com") return "sales_office";
  if (email === "jack@marblebee.com") return "outlook";
  if (email === "bilalhaider.tech@gmail.com") return "test";

  return "unknown";
}

// ======================================================
// 9ï¸â£ MAIN PIPELINE
// ======================================================
const results = [];

for (const item of items) {
  const json = item.json || {};
  const binary = item.binary || {};

  const isOutlook = !!json.toRecipients || !!json.from?.emailAddress;

  const from_email = isOutlook
    ? json.from?.emailAddress?.address || null
    : json.from?.value?.[0]?.address || null;

  const from_name = isOutlook
    ? json.from?.emailAddress?.name || null
    : json.from?.value?.[0]?.name || null;

  const to_email = isOutlook
    ? json.toRecipients?.[0]?.emailAddress?.address || null
    : json.to?.value?.[0]?.address || null;

  const to_name = isOutlook
    ? json.toRecipients?.[0]?.emailAddress?.name || null
    : json.to?.value?.[0]?.name || null;

  const htmlContent = isOutlook
    ? json.body?.content || ""
    : json.textAsHtml || "";

  // ======================================================
  // CORE FIXED PIPELINE
  // ======================================================
  const latestMessage = extractLatestMessage(htmlContent);
  const fullThread = cleanThreadHistory(htmlContent);

  const totalLength = fullThread.length;

  let threadOutput =
    totalLength > BATCH_THRESHOLD
      ? splitByChars(fullThread, MAX_CHARS)
      : fullThread;

  // ======================================================
  // OUTPUT
  // ======================================================
  results.push({
    json: {
      id: json.id || null,
      thread_id: isOutlook ? json.conversationId : json.threadId,
      message_id: isOutlook ? json.internetMessageId : json.messageId,

      subject: json.subject || null,

      date: isOutlook
        ? json.receivedDateTime || json.sentDateTime
        : json.date,

      from_email,
      from_name,
      to_email,
      to_name,

      message_text: latestMessage,
      thread_history: threadOutput,
      thread_length: totalLength,

      email_processor: getEmailProcessor(to_email),

      has_attachments:
        (json.hasAttachments || Object.keys(binary).length > 0) ?? false
    },
    binary
  });
}

return results;

