const items = $input.all();

return items.map(item => {

  // Get document array safely
  const documents = item.json.data?.Document || [];
  const fileCount = Array.isArray(documents) ? documents.length : 0;

  let fileNamesString = null;

  if (fileCount === 1) {
    fileNamesString = 'Document';
  } 
  else if (fileCount > 1) {
    fileNamesString = documents
      .map((_, index) => `Document_${index}`)
      .join(',');
  }

  // Get message text safely
  let message = item.json.data?.Message || '';

  // ð¹ Step 1: Normalize wrong line breaks (/n â \n)
  message = message.replace(/\/n/g, '\n');

  // ð¹ Step 2: Remove old signature starting from "Regards,"
  message = message.replace(/Regards,[\s\S]*/i, '').trim();

  // ð¹ Step 3: Convert text to HTML
  const formattedMessage = message
    .replace(/\r\n/g, '\n')
    .replace(/\n/g, '<br>');

  // ð¹ Step 4: Append clean signature
  const htmlMessage = `
    ${formattedMessage}
    <br><br>
    Regards,<br>
    Jack<br><br>
    <span style="color:green;">
      <b>MarbleBee</b><br>
      One-Step Destination for Custom Marble Products - from Sculptures to Slabs
    </span><br>
    <a href="https://MarbleBee.com" target="_blank" style="color:green; text-decoration:none;">
      MarbleBee.com
    </a>
  `;

  return {
    json: {
      ...item.json,
      document_count: fileCount,
      document_labels: fileNamesString,
      html_message: htmlMessage
    },
    binary: item.binary
  };
});

// Get AI output
