} catch (e) {
  rawText = "";
}

let parsed;

try {
  parsed = JSON.parse(rawText);
} catch (e) {
  // fallback if parsing fails
  parsed = {
    category: "important",
    confidence: 0.5,
    is_human: true
  };
}

const category = parsed.category || "important";
const confidence = parsed.confidence ?? 0.5;
const isHuman = parsed.is_human ?? true;

// ð¥ CORE DECISION LOGIC
const shouldProcess =
  category === "important" ||
  isHuman === true ||
  confidence < 0.7;

return [{
  json: {
    ai_raw: rawText,        // optional debug
    category,
    confidence,
    is_human: isHuman,
    should_process: shouldProcess
  }
}];

// ======================================================
