// ======================================================
const intent = parsed.intent || "unclear";
const isQuestion = parsed.is_question ?? false;
const question = parsed.question || "";
const response = parsed.response || "";

// ======================================================
// 4ï¸â£ RETURN CLEAN OUTPUT
// ======================================================
